# Assuming a function get_astel_nft_balance() exists to query the player's NFT balance
def can_earn_crypto(required_nfts):
    player_balance = get_astel_nft_balance()
    return player_balance >= required_nfts

# Example usage
if can_earn_crypto(1):
    print("Player can earn cryptocurrency.")
else:
    print("Player needs more Astel NFTs to earn cryptocurrency.")
